// This file is a stub. The actual service worker is generated by next-pwa at build time.
// During development, this file acts as a placeholder to prevent 404 errors.

self.addEventListener("install", (event) => {
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener("fetch", (event) => {
  // Passthrough - next-pwa will replace this with proper caching strategies at build
  event.respondWith(fetch(event.request));
});
